/// <reference lib="webworker" />

// Service worker for agent-workbench mobile-web PWA.
// Cache-first strategy for app shell assets, network-first for API calls.
// Generated by Vite + vite-plugin-pwa with custom workbox config.

declare const self: ServiceWorkerGlobalScope;

const CACHE_NAME = "agent-workbench-v1";
const APP_SHELL_URLS = ["/", "/index.html", "/manifest.json"];

// Install: pre-cache app shell
self.addEventListener("install", (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(APP_SHELL_URLS).catch((err) => {
        console.warn("[sw] Pre-cache failed for some assets:", err);
      });
    })
  );
  // Activate immediately — don't wait for old tabs to close
  self.skipWaiting();
});

// Activate: clean old caches
self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches.keys().then((names) => {
      return Promise.all(
        names.filter((n) => n !== CACHE_NAME).map((n) => caches.delete(n))
      );
    })
  );
  // Take control of all clients immediately
  self.clients.claim();
});

// Fetch: cache-first for app shell, network-first for API calls
self.addEventListener("fetch", (event) => {
  const { request } = event;
  const url = new URL(request.url);

  // Skip non-GET requests
  if (request.method !== "GET") return;

  // API calls — network first, fall back to cache
  if (url.pathname.startsWith("/api/") || url.pathname.match(/^\/(session|file|git|tool|health|info|event|permission|provider|agent|config|message|plan)/)) {
    event.respondWith(networkFirst(request));
    return;
  }

  // App shell assets — cache first, fall back to network
  event.respondWith(cacheFirst(request));
});

async function cacheFirst(request: Request): Promise<Response> {
  const cache = await caches.open(CACHE_NAME);
  const cached = await cache.match(request);
  if (cached) return cached;

  try {
    const response = await fetch(request);
    if (response.ok) {
      cache.put(request, response.clone());
    }
    return response;
  } catch {
    // Offline fallback for navigation requests
    if (request.mode === "navigate") {
      const fallback = await cache.match("/index.html");
      if (fallback) return fallback;
    }
    return new Response("Offline — app shell not cached yet", { status: 503 });
  }
}

async function networkFirst(request: Request): Promise<Response> {
  try {
    const response = await fetch(request);
    const cache = await caches.open(CACHE_NAME);
    cache.put(request, response.clone());
    return response;
  } catch {
    const cached = await caches.match(request);
    if (cached) return cached;
    return new Response("Offline — data not available", { status: 503 });
  }
}
